    <div style="font-size:12px;color:var(--gray-l);margin-bottom:10px">\uAE30\uC874 \uB514\uC790\uC778\uC740 \uC720\uC9C0\uD558\uACE0, \uCF1C\uBA74 \uC0C8\uB85C\uC6B4 \uB514\uC790\uC778(\uD0ED/\uCE74\uB4DC/\uBAA8\uB2EC/\uD604\uD669\uD310 \uB4F1)\uC744 \uC801\uC6A9\uD569\uB2C8\uB2E4.</div>
