            <input type="range" id="ed-phbg-posy" min="0" max="100" step="1" value="${Number((ee=e.detailHeaderBgPosY)!=null?ee:50)||50}" style="flex:1;accent-color:var(--blue)" oninput="document.getElementById('ed-phbg-posy-val').textContent=this.value+'%'; edPhbgSyncFromInputs()">
            <span id="ed-phbg-posy-val" style="font-size:11px;color:var(--gray-l);min-width:40px;text-align:right;font-weight:700">${Number((te=e.detailHeaderBgPosY)!=null?te:50)||50}%</span>
          </div>
